    "z": <float>
  },
  "delta_scale": {                        // Scale delta (offset)
    "x": <float>,
    "y": <float>,
    "z": <float>
  },
  "triggerring_events": [                 // List of events during the Trigger process, these events will be triggered witin one frame.
        // 0 or more event units
        {
